// ============================================================
// BUILD ALERT PAYLOAD — Workflow 2, Node 2
// ============================================================

const data = $json;
const emp = data.employee || {};
const allDeals = data.deals || [];
const max = data.maxDealsPerMsg || 8;
const dealListUrl = data.dealListUrl || `${data.bitrixDomain}/crm/deal/`;
const senderName = data.fromName || 'Averlon CRM';

// Determine current alert time label (IST-aware)
const now = new Date();
const IST_OFFSET_MS = 5.5 * 60 * 60 * 1000;
const nowIST = new Date(now.getTime() + IST_OFFSET_MS);
const hour = nowIST.getUTCHours();

let alertLabel = '10:00 AM';
if (hour === 13) alertLabel = '1:00 PM';
else if (hour === 17) alertLabel = '5:00 PM';
else if (hour === 18) alertLabel = '6:30 PM';

// ---- VALIDATE & LIMIT TO MAX 8 ----
if (!Array.isArray(allDeals) || allDeals.length === 0) {
  return [{ json: { error: "Deals data is missing or invalid", debug: data } }];
}

const shownDeals = allDeals.slice(0, max);
const remainingCount = allDeals.length - shownDeals.length;

// ---- BUILD DEAL LIST TEXT (for Bitrix24 notification) ----
function dealStatusLabel(deal) {
  if (deal.daysLeft < 0) return `⚠️ OVERDUE by ${Math.abs(deal.daysLeft)} day(s)`;
  if (deal.daysLeft === 0) return `🟠 Due TODAY`;
  return `🔔 Due in ${deal.daysLeft} day(s)`;
}

let bitrixBody = `📋 Upcoming Deal Alerts — ${alertLabel}\n\n`;
bitrixBody += `Hi ${emp.name || 'User'},\n\nYou have ${data.totalDeals} deal(s) requiring your attention:\n\n`;

shownDeals.forEach((deal, i) => {
  const subject = deal.title || 'Unnamed Deal';
  const dueDate = deal.renewalDateFormatted || 'No date';
  const url = deal.url || data.bitrixDomain;

  bitrixBody += `${i + 1}. *${subject}*\n`;
  bitrixBody += `   📅 Due: ${dueDate}\n`;
  bitrixBody += `   ${dealStatusLabel(deal)}\n`;
  bitrixBody += `   🔗 [Open Deal](${url})\n\n`;
});

if (remainingCount > 0) {
  bitrixBody += `➕ And *${remainingCount} more deal(s)* remaining.\n`;
  bitrixBody += `[Click here to view all deals](${dealListUrl})\n\n`;
}

bitrixBody += `— ${senderName}`;

// ---- BUILD RESPONSIVE HTML EMAIL (for Outlook + all devices) ----
// Uses: media queries, fluid widths, stacked card layout on mobile,
// MSO conditional comments for Outlook table-width fix.

function getStatusStyle(daysLeft) {
  if (daysLeft < 0) return { color: '#C0392B', bg: '#FDECEA', text: `Overdue by ${Math.abs(daysLeft)} day(s)` };
  if (daysLeft === 0) return { color: '#B7600A', bg: '#FEF3E2', text: 'Due Today' };
  return { color: '#0F6E56', bg: '#E6F4F1', text: `Due in ${daysLeft} day(s)` };
}

function dealCardHtml(deal, index) {
  const { color, bg, text: statusText } = getStatusStyle(deal.daysLeft);
  const subject = deal.title || 'Unnamed Deal';
  const dueDate = deal.renewalDateFormatted || 'No date';
  const url = deal.url || '#';

  // Each deal is a self-contained block that stacks naturally on mobile.
  // No multi-column table rows — just a single bordered card per deal.
  return `
    <!--[if mso]><table width="100%" cellpadding="0" cellspacing="0"><tr><td><![endif]-->
    <div style="
      border: 1px solid #E2E0D8;
      border-radius: 8px;
      margin-bottom: 12px;
      overflow: hidden;
      background: #ffffff;
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Arial, sans-serif;
    ">
      <!-- Deal header row -->
      <div style="
        background: #F7F6F1;
        padding: 10px 16px;
        border-bottom: 1px solid #E2E0D8;
      ">
        <span style="
          font-size: 13px;
          font-weight: 700;
          color: #2C2C2A;
          display: inline-block;
          width: 100%;
          box-sizing: border-box;
        ">${index + 1}. ${subject}</span>
      </div>

      <!-- Deal details: date + status + action -->
      <div style="padding: 12px 16px;">

        <!-- Due date -->
        <div style="margin-bottom: 10px;">
          <span style="
            display: inline-block;
            font-size: 11px;
            color: #888780;
            font-weight: 600;
            text-transform: uppercase;
            letter-spacing: 0.5px;
            margin-bottom: 3px;
          ">Due Date</span><br>
          <span style="font-size: 14px; color: #2C2C2A;">📅 ${dueDate}</span>
        </div>

        <!-- Status badge + action button side by side where space allows -->
        <!--[if mso]>
        <table width="100%" cellpadding="0" cellspacing="0"><tr>
          <td style="width:60%;"><![endif]-->
        <div style="display: inline-block; vertical-align: middle; margin-bottom: 6px;">
          <span style="
            display: inline-block;
            background: ${bg};
            color: ${color};
            font-size: 12px;
            font-weight: 600;
            padding: 4px 12px;
            border-radius: 20px;
          ">${statusText}</span>
        </div>
        <!--[if mso]></td><td style="width:40%;text-align:right;"><![endif]-->
        <div style="display: inline-block; vertical-align: middle; float: right; margin-bottom: 6px;">
          <a href="${url}" style="
            display: inline-block;
            background: #185FA5;
            color: #ffffff;
            font-size: 13px;
            font-weight: 600;
            padding: 6px 16px;
            border-radius: 6px;
            text-decoration: none;
          ">View Deal →</a>
        </div>
        <!--[if mso]></td></tr></table><![endif]-->
        <div style="clear:both;"></div>

      </div>
    </div>
    <!--[if mso]></td></tr></table><![endif]-->
  `;
}

const dealCardsHtml = shownDeals.map((d, i) => dealCardHtml(d, i)).join('');

const remainingHtml = remainingCount > 0 ? `
  <div style="
    margin: 16px 0;
    padding: 14px 18px;
    background: #E6F1FB;
    border-radius: 8px;
    font-size: 14px;
    color: #ffffff;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Arial, sans-serif;
  ">
    And <strong>${remainingCount} more deal(s)</strong> not shown here.<br>
    <a href="${dealListUrl}" style="
      color: #ffffff;
      font-weight: 700;
      text-decoration: underline;
    ">Click here to view all deals →</a>
  </div>` : '';

const emailHtml = `
<!DOCTYPE html>
<html lang="en" xmlns="http://www.w3.org/1999/xhtml" xmlns:v="urn:schemas-microsoft-com:vml" xmlns:o="urn:schemas-microsoft-com:office:office">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <meta http-equiv="X-UA-Compatible" content="IE=edge">
  <meta name="x-apple-disable-message-reformatting">
  <title>Deal Alerts</title>
  <!--[if mso]>
  <noscript>
    <xml>
      <o:OfficeDocumentSettings>
        <o:AllowPNG/>
        <o:PixelsPerInch>96</o:PixelsPerInch>
      </o:OfficeDocumentSettings>
    </xml>
  </noscript>
  <![endif]-->
  <style type="text/css">
    /* === RESET === */
    body, table, td, a { -webkit-text-size-adjust: 100%; -ms-text-size-adjust: 100%; }
    table, td { mso-table-lspace: 0pt; mso-table-rspace: 0pt; }
    img { -ms-interpolation-mode: bicubic; border: 0; outline: none; text-decoration: none; }
    body { margin: 0 !important; padding: 0 !important; background-color: #F4F4F0; width: 100% !important; }

    /* === MOBILE RESPONSIVE === */
    @media screen and (max-width: 600px) {
      .email-wrapper {
        width: 100% !important;
        margin: 0 !important;
        border-radius: 0 !important;
      }
      .email-header {
        padding: 22px 18px !important;
        border-radius: 0 !important;
      }
      .email-header h1 {
        font-size: 18px !important;
      }
      .email-body {
        padding: 18px 14px 0 !important;
      }
      .email-deals {
        padding: 0 14px !important;
      }
      .email-footer {
        padding: 18px 14px !important;
      }
      .remaining-block {
        margin: 12px 14px !important;
      }
    }

    @media screen and (max-width: 400px) {
      .email-header h1 {
        font-size: 16px !important;
      }
      .email-header .label-brand {
        font-size: 10px !important;
      }
    }
  </style>
</head>
<body style="margin:0;padding:0;background-color:#F4F4F0;">

  <!-- Outer wrapper table (100% width for all clients) -->
  <!--[if mso]>
  <table width="100%" cellpadding="0" cellspacing="0" border="0" bgcolor="#F4F4F0"><tr><td align="center">
  <table width="620" cellpadding="0" cellspacing="0" border="0"><tr><td>
  <![endif]-->

  <div style="max-width:620px;margin:32px auto;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;">

    <!-- Card wrapper -->
    <table class="email-wrapper" width="100%" cellpadding="0" cellspacing="0" border="0"
      style="background:#ffffff;border-radius:12px;overflow:hidden;border:1px solid #D3D1C7;">

      <!-- HEADER -->
      <tr>
        <td class="email-header" style="background:#185FA5;padding:28px 32px;">
          <div class="label-brand" style="font-size:11px;color:#ffffff;font-weight:700;letter-spacing:1.2px;text-transform:uppercase;margin-bottom:6px;">${senderName}</div>
          <h1 style="margin:0;color:#ffffff;font-size:22px;font-weight:700;line-height:1.3;">Upcoming Deal Alerts</h1>
          <div style="color:#ffffff; font-size:13px; margin-top:6px; font-weight:700;">
  ${alertLabel} · ${data.runDate}
</div>
        </td>
      </tr>

      <!-- INTRO -->
      <tr>
        <td class="email-body" style="padding:24px 32px 0;">
          <p style="font-size:15px;color:#2C2C2A;margin:0 0 6px;"><strong>Hi ${emp.name || 'User'},</strong></p>
          <p style="font-size:14px;color:#5F5E5A;margin:0 0 0;">You have <strong>${data.totalDeals} deal(s) requiring your attention</strong>.</p>
        </td>
      </tr>

      <!-- DEALS LIST (card per deal — fully responsive) -->
      <tr>
        <td class="email-deals" style="padding:18px 32px 0;">
          ${dealCardsHtml}
        </td>
      </tr>

      <!-- REMAINING -->
      ${remainingCount > 0 ? `
      <tr>
        <td class="remaining-block" style="padding:0 32px;">
          ${remainingHtml}
        </td>
      </tr>` : ''}

      <!-- FOOTER -->
      <tr>
        <td class="email-footer" style="padding:20px 32px;border-top:1px solid #E8E8E8;margin-top:16px;">
          <p style="font-size:12px;color:#888780;margin:0;">This is an automated alert from <strong>${senderName}</strong>. Please do not reply to this email.</p>
        </td>
      </tr>

    </table>
    <!-- End card wrapper -->

  </div>

  <!--[if mso]>
  </td></tr></table>
  </td></tr></table>
  <![endif]-->

</body>
</html>`;

// ---- BUILD CHAT MESSAGE (for Bitrix24 Chat) ----
let chatBody = `Upcoming Deal Alerts — ${alertLabel}\n\n`;
chatBody += `Hi ${emp.name || 'User'}, you have *${data.totalDeals} deal(s)* needing attention:\n\n`;

shownDeals.forEach((deal, i) => {
  const subject = deal.title || 'Unnamed Deal';
  const dueDate = deal.renewalDateFormatted || 'No date';
  const url = deal.url || data.bitrixDomain;
  chatBody += `${i + 1}. *${subject}*\n`;
  chatBody += `   📅 ${dueDate} — ${dealStatusLabel(deal)}\n`;
  chatBody += `   🔗 ${url}\n\n`;
});

if (remainingCount > 0) {
  chatBody += `➕ *${remainingCount} more deal(s)* not shown.\n`;
  chatBody += `View all: ${dealListUrl}\n`;
}
chatBody += `\n— ${senderName}`;

return [{
  json: {
    ...data,
    payload: {
      bitrixTitle: `Upcoming Deal Alerts — ${alertLabel}`,
      bitrixBody: bitrixBody,
      chatBody: chatBody,
      emailSubject: `[${alertLabel}] ${data.totalDeals} Deal Alert(s) — ${emp.name}`,
      emailHtml: emailHtml,
      recipientEmail: emp.email || 'no-email@example.com',
      recipientName: emp.name || 'User',
      bitrixUserId: emp.bitrixUserId
    }
  }
}];
